import * as THREE from 'three';

const FACES = [
  { filename: "003983.jpg", age: 0.16469654981046916, gender: -0.7329808135982603, skinTone: -0.15129969520494344, dataUri: "data:image/jpeg;base64," },
  { filename: "016605.jpg", age: 0.5434773332439363, gender: 0.5339976090472192, skinTone: -0.7075379665941001, dataUri: "data:image/jpeg;base64," },
  { filename: "016709.jpg", age: 0.7027923685964197, gender: -0.8316282324492932, skinTone: 0.13326376127079131, dataUri: "data:image/jpeg;base64," },
  { filename: "020172.jpg", age: 0.9249435367062687, gender: 0.7905912870075553, skinTone: -0.8708511447068304, dataUri: "data:image/jpeg;base64," },
  { filename: "030754.jpg", age: -0.10116452826187015, gender: -0.8266255339141936, skinTone: -0.33407022375613454, dataUri: "data:image/jpeg;base64," },
  { filename: "032437.jpg", age: 0.1355423251632601, gender: 0.7487381475046277, skinTone: 0.6551322040613741, dataUri: "data:image/jpeg;base64," },
  { filename: "038300.jpg", age: -0.24860070259310305, gender: 0.8115723026450723, skinTone: 0.3542017120867968, dataUri: "data:image/jpeg;base64," },
  { filename: "042926.jpg", age: 0.9137661364395172, gender: -0.9584829258732498, skinTone: -0.686672527063638, dataUri: "data:image/jpeg;base64," },
  { filename: "054550.jpg", age: 0.3445372112561017, gender: 0.6036411224398762, skinTone: 0.25481081032194197, dataUri: "data:image/jpeg;base64," },
  { filename: "063886.jpg", age: -0.21516853538341818, gender: 0.7252255892381072, skinTone: 0.3178713622968644, dataUri: "data:image/jpeg;base64," },
  { filename: "081746.jpg", age: 0.43655939335003496, gender: 0.8514379077125341, skinTone: 0.7391122567933053, dataUri: "data:image/jpeg;base64," },
  { filename: "105328.jpg", age: -0.8662402103189378, gender: 0.864451562333852, skinTone: -0.7884423415176571, dataUri: "data:image/jpeg;base64," },
  { filename: "119244.jpg", age: -0.36713434555567803, gender: 0.8799426570069045, skinTone: 0.6710009262897074, dataUri: "data:image/jpeg;base64," },
  { filename: "139091.jpg", age: -0.2707925744354725, gender: 1.0244354037567973, skinTone: -0.8208603514824062, dataUri: "data:image/jpeg;base64," },
  { filename: "183263.jpg", age: 0.8680881633516401, gender: -0.8963526483159513, skinTone: 0.8738323578611017, dataUri: "data:image/jpeg;base64," },
  { filename: "187076.jpg", age: 0.03250908069312573, gender: -0.6878714871592819, skinTone: 0.940690335445106, dataUri: "data:image/jpeg;base64," }
];

const COLS = 4;
const ROWS = 4;
const SPACING = 2.6;
const RADIUS = 1.0;
const FACE_RADIUS = RADIUS * 0.92;
const AXIS_SCALE = 5.0;
const SHRINK_TO = 0.5;
const LERP = 0.08;
const MAX_STAGE = 4;
const CAM_BASE = 21.6;
const CAM_WIDE = 30.0;
const CAM_ORBIT_Y = 0.55;
const CAM_ORBIT_X = 0.28;
const CAM_SPIN_PERIOD = 20;

// --- hyperspace cloud (final beat) ---
const CLOUD_N = 6000;
const DIM = 8;
const CLUSTERS = 6;
const HD_SPREAD = 2.4;   // cluster-centre spread in D-space
const HD_SIGMA = 0.7;    // within-cluster gaussian sigma
const CLOUD_GAIN = 1.7;  // D-space → world-space scale
const TUMBLE_RATE = 0.5; // base angular speed of the projection basis
const POINT_SIZE = 240;  // gl_PointSize = POINT_SIZE * pixelRatio / dist
const CLOUD_PALETTE = [0x49bcff, 0x175fff, 0x00dcc6, 0xc84cff, 0x7f47ff, 0x9ed8ff];

// Deterministic so the cloud reads the same on every run (mulberry32).
function makeRng(seed) {
  let a = seed >>> 0;
  return function () {
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function gaussian(rng) {
  let u = 0;
  while (u === 0) u = rng();
  return Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * rng());
}

function hexRGB(hex) {
  return [((hex >> 16) & 255) / 255, ((hex >> 8) & 255) / 255, (hex & 255) / 255];
}

function vecNormalize(v) {
  let s = 0;
  for (let i = 0; i < v.length; i++) s += v[i] * v[i];
  s = Math.sqrt(s) || 1;
  for (let i = 0; i < v.length; i++) v[i] /= s;
}

function vecSubProj(v, onto) {
  let dot = 0;
  for (let i = 0; i < v.length; i++) dot += v[i] * onto[i];
  for (let i = 0; i < v.length; i++) v[i] -= dot * onto[i];
}

export default function init({ canvas }) {
  const renderer = new THREE.WebGLRenderer({ canvas, antialias: true, alpha: true });
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.setClearColor(0x0a0e1a, 1);
  const w = canvas.clientWidth || canvas.width;
  const h = canvas.clientHeight || canvas.height;
  renderer.setSize(w, h, false);

  const scene = new THREE.Scene();
  const camera = new THREE.PerspectiveCamera(35, w / h, 0.1, 200);
  camera.position.set(0, 0, CAM_BASE);
  camera.lookAt(0, 0, 0);

  scene.add(new THREE.AmbientLight(0xffffff, 0.6));
  const key = new THREE.DirectionalLight(0xffffff, 0.85);
  key.position.set(4, 6, 8);
  scene.add(key);
  const fill = new THREE.DirectionalLight(0x88aaff, 0.35);
  fill.position.set(-6, -3, 4);
  scene.add(fill);

  const loader = new THREE.TextureLoader();
  const sphereGeo = new THREE.SphereGeometry(RADIUS, 48, 32);
  const faceGeo = new THREE.CircleGeometry(FACE_RADIUS, 48);
  const sphereMat = new THREE.MeshStandardMaterial({
    color: 0x1a2240,
    roughness: 0.6,
    metalness: 0.1,
    transparent: true,
  });

  const spheres = [];
  const facePlanes = [];
  const faceMats = [];
  const textures = [];
  const layouts = [[], [], [], []];

  const xOffset = -((COLS - 1) * SPACING) / 2;
  const yOffset = ((ROWS - 1) * SPACING) / 2;

  FACES.forEach((face, i) => {
    const col = i % COLS;
    const row = Math.floor(i / COLS);
    const gx = xOffset + col * SPACING;
    const gy = yOffset - row * SPACING;
    layouts[0].push(new THREE.Vector3(gx, gy, 0));
    layouts[1].push(new THREE.Vector3(face.age * AXIS_SCALE, 0, 0));
    layouts[2].push(new THREE.Vector3(face.age * AXIS_SCALE, face.gender * AXIS_SCALE, 0));
    layouts[3].push(new THREE.Vector3(face.age * AXIS_SCALE, face.gender * AXIS_SCALE, face.skinTone * AXIS_SCALE));

    const sphere = new THREE.Mesh(sphereGeo, sphereMat);
    sphere.position.copy(layouts[0][i]);
    scene.add(sphere);
    spheres.push(sphere);

    const tex = loader.load(face.dataUri);
    tex.colorSpace = THREE.SRGBColorSpace;
    tex.minFilter = THREE.LinearFilter;
    tex.magFilter = THREE.LinearFilter;
    tex.generateMipmaps = false;
    const mat = new THREE.MeshBasicMaterial({ map: tex, transparent: true });
    const plane = new THREE.Mesh(faceGeo, mat);
    plane.position.copy(layouts[0][i]);
    scene.add(plane);

    facePlanes.push(plane);
    faceMats.push(mat);
    textures.push(tex);
  });

  const axisLen = AXIS_SCALE * 1.2;
  const xAxisGeo = new THREE.BufferGeometry().setFromPoints([
    new THREE.Vector3(-axisLen, 0, 0),
    new THREE.Vector3(axisLen, 0, 0),
  ]);
  const yAxisGeo = new THREE.BufferGeometry().setFromPoints([
    new THREE.Vector3(0, -axisLen, 0),
    new THREE.Vector3(0, axisLen, 0),
  ]);
  const zAxisGeo = new THREE.BufferGeometry().setFromPoints([
    new THREE.Vector3(0, 0, -axisLen),
    new THREE.Vector3(0, 0, axisLen),
  ]);
  const xAxisMat = new THREE.LineBasicMaterial({ color: 0xe8e6e1, transparent: true, opacity: 0 });
  const yAxisMat = new THREE.LineBasicMaterial({ color: 0xe8e6e1, transparent: true, opacity: 0 });
  const zAxisMat = new THREE.LineBasicMaterial({ color: 0xe8e6e1, transparent: true, opacity: 0 });
  scene.add(new THREE.Line(xAxisGeo, xAxisMat));
  scene.add(new THREE.Line(yAxisGeo, yAxisMat));
  scene.add(new THREE.Line(zAxisGeo, zAxisMat));

  // --- hyperspace cloud ---
  const rng = makeRng(0x5eedface);
  const centers = [];
  for (let c = 0; c < CLUSTERS; c++) {
    const ctr = new Float32Array(DIM);
    for (let d = 0; d < DIM; d++) ctr[d] = (rng() * 2 - 1) * HD_SPREAD;
    centers.push(ctr);
  }

  const hd = new Float32Array(CLOUD_N * DIM); // point coords in D-space
  const cloudPos = new Float32Array(CLOUD_N * 3); // projected, refilled each frame
  const cloudCol = new Float32Array(CLOUD_N * 3);
  const cloudSeed = new Float32Array(CLOUD_N);
  for (let i = 0; i < CLOUD_N; i++) {
    const c = i % CLUSTERS;
    const ctr = centers[c];
    for (let d = 0; d < DIM; d++) hd[i * DIM + d] = ctr[d] + gaussian(rng) * HD_SIGMA;
    const rgb = hexRGB(CLOUD_PALETTE[c]);
    cloudCol[i * 3] = rgb[0];
    cloudCol[i * 3 + 1] = rgb[1];
    cloudCol[i * 3 + 2] = rgb[2];
    cloudSeed[i] = rng();
  }

  const cloudGeo = new THREE.BufferGeometry();
  cloudGeo.setAttribute('position', new THREE.BufferAttribute(cloudPos, 3));
  cloudGeo.setAttribute('aColor', new THREE.BufferAttribute(cloudCol, 3));
  cloudGeo.setAttribute('aSeed', new THREE.BufferAttribute(cloudSeed, 1));

  const cloudMat = new THREE.ShaderMaterial({
    transparent: true,
    depthWrite: false,
    blending: THREE.AdditiveBlending,
    uniforms: {
      uOpacity: { value: 0 },
      uSize: { value: POINT_SIZE },
      uTime: { value: 0 },
      uPixelRatio: { value: renderer.getPixelRatio() },
    },
    vertexShader: `
      attribute vec3 aColor;
      attribute float aSeed;
      uniform float uSize;
      uniform float uPixelRatio;
      varying vec3 vColor;
      varying float vSeed;
      void main() {
        vColor = aColor;
        vSeed = aSeed;
        vec4 mv = modelViewMatrix * vec4(position, 1.0);
        gl_PointSize = uSize * uPixelRatio / max(-mv.z, 0.1);
        gl_Position = projectionMatrix * mv;
      }
    `,
    fragmentShader: `
      uniform float uOpacity;
      uniform float uTime;
      varying vec3 vColor;
      varying float vSeed;
      void main() {
        float r = length(gl_PointCoord - 0.5);
        if (r > 0.5) discard;
        float glow = pow(smoothstep(0.5, 0.0, r), 1.6);
        float tw = 0.7 + 0.3 * sin(uTime * 1.5 + vSeed * 6.2831853);
        gl_FragColor = vec4(vColor, glow * uOpacity * tw);
      }
    `,
  });
  const cloudPoints = new THREE.Points(cloudGeo, cloudMat);
  cloudPoints.frustumCulled = false;
  scene.add(cloudPoints);

  // Orthonormal projection basis in D-space; rotating it tumbles the cloud
  // through its hidden dimensions.
  const basis = [new Float32Array(DIM), new Float32Array(DIM), new Float32Array(DIM)];
  basis[0][0] = 1;
  basis[1][1] = 1;
  basis[2][2] = 1;
  const TUMBLE_PLANES = [[0, 3], [1, 5], [2, 6], [4, 7]];
  let tumblePhase = 0;
  let tumbleFrames = 0;

  function tumble(dt, rate) {
    tumblePhase += dt;
    for (let k = 0; k < TUMBLE_PLANES.length; k++) {
      const p = TUMBLE_PLANES[k][0];
      const q = TUMBLE_PLANES[k][1];
      const ang = rate * dt * (0.6 + 0.4 * Math.sin(tumblePhase * 0.2 + k));
      const cs = Math.cos(ang);
      const sn = Math.sin(ang);
      for (let b = 0; b < 3; b++) {
        const vec = basis[b];
        const a = vec[p];
        const bb = vec[q];
        vec[p] = a * cs - bb * sn;
        vec[q] = a * sn + bb * cs;
      }
    }
    if (++tumbleFrames % 90 === 0) {
      vecNormalize(basis[0]);
      vecSubProj(basis[1], basis[0]);
      vecNormalize(basis[1]);
      vecSubProj(basis[2], basis[0]);
      vecSubProj(basis[2], basis[1]);
      vecNormalize(basis[2]);
    }
  }

  function projectCloud(gain) {
    const u = basis[0];
    const v = basis[1];
    const wv = basis[2];
    for (let i = 0; i < CLOUD_N; i++) {
      const o = i * DIM;
      let x = 0;
      let y = 0;
      let z = 0;
      for (let d = 0; d < DIM; d++) {
        const val = hd[o + d];
        x += val * u[d];
        y += val * v[d];
        z += val * wv[d];
      }
      const p = i * 3;
      cloudPos[p] = x * gain;
      cloudPos[p + 1] = y * gain;
      cloudPos[p + 2] = z * gain;
    }
    cloudGeo.attributes.position.needsUpdate = true;
  }

  let cloudTime = 0;

  let stage = 0;
  let targetT = 0;
  let currentT = 0;
  let currentScale = 1;

  const LAYOUT_MAX = layouts.length - 1;
  function applyLayout(t) {
    const idx = Math.floor(t);
    const frac = t - idx;
    const fromArr = layouts[Math.min(idx, LAYOUT_MAX)];
    const toArr = layouts[Math.min(idx + 1, LAYOUT_MAX)];
    for (let i = 0; i < spheres.length; i++) {
      spheres[i].position.lerpVectors(fromArr[i], toArr[i], frac);
    }
    const s = 1 + (SHRINK_TO - 1) * Math.min(t, 1);
    currentScale = s;
    for (let i = 0; i < spheres.length; i++) {
      spheres[i].scale.setScalar(s);
      facePlanes[i].scale.setScalar(s);
    }

    // Final beat (t in [3,4]): faces, spheres and axes give way to the cloud.
    const w = THREE.MathUtils.clamp(t - 3, 0, 1);
    const faceFade = 1 - w;
    // Once the cloud is showing, stop the (now-transparent) faces and spheres
    // writing depth, or they punch circular holes in the additive points behind.
    const writeDepth = w === 0;
    sphereMat.opacity = faceFade;
    sphereMat.depthWrite = writeDepth;
    for (let i = 0; i < faceMats.length; i++) {
      faceMats[i].opacity = faceFade;
      faceMats[i].depthWrite = writeDepth;
    }
    xAxisMat.opacity = 0.45 * THREE.MathUtils.clamp(t, 0, 1) * faceFade;
    yAxisMat.opacity = 0.45 * THREE.MathUtils.clamp(t - 1, 0, 1) * faceFade;
    zAxisMat.opacity = 0.45 * THREE.MathUtils.clamp(t - 2, 0, 1) * faceFade;
    cloudMat.uniforms.uOpacity.value = w;
  }

  let spinAngle = 0;
  const SPIN_RATE = (Math.PI * 2) / CAM_SPIN_PERIOD;
  function applyCamera(t) {
    const t3 = THREE.MathUtils.clamp(t - 2, 0, 1);
    const w = THREE.MathUtils.clamp(t - 3, 0, 1);
    const angleY = t3 * CAM_ORBIT_Y + spinAngle;
    const angleX = t3 * CAM_ORBIT_X;
    const r = CAM_BASE + (CAM_WIDE - CAM_BASE) * w;
    camera.position.x = Math.sin(angleY) * r * Math.cos(angleX);
    camera.position.z = Math.cos(angleY) * r * Math.cos(angleX);
    camera.position.y = Math.sin(angleX) * r;
    camera.lookAt(0, 0, 0);
  }

  const camDir = new THREE.Vector3();
  function orientFaces() {
    for (let i = 0; i < facePlanes.length; i++) {
      const plane = facePlanes[i];
      const sphere = spheres[i];
      camDir.subVectors(camera.position, sphere.position).normalize();
      plane.position.copy(sphere.position).addScaledVector(camDir, RADIUS * currentScale * 1.02);
      plane.lookAt(camera.position);
    }
  }

  let raf = 0;
  let lastTime = 0;
  function loop(now) {
    const dt = lastTime ? (now - lastTime) / 1000 : 0;
    lastTime = now;
    currentT += (targetT - currentT) * LERP;
    if (targetT >= 3) {
      const spinWeight = THREE.MathUtils.clamp(currentT - 2, 0, 1);
      spinAngle += dt * SPIN_RATE * spinWeight;
      if (spinAngle > Math.PI) spinAngle -= 2 * Math.PI;
      if (spinAngle < -Math.PI) spinAngle += 2 * Math.PI;
    } else {
      spinAngle += (0 - spinAngle) * LERP;
    }
    applyLayout(currentT);
    applyCamera(currentT);
    orientFaces();
    const w = THREE.MathUtils.clamp(currentT - 3, 0, 1);
    if (w > 0.001) {
      cloudTime += dt;
      cloudMat.uniforms.uTime.value = cloudTime;
      tumble(dt, TUMBLE_RATE * w);
      projectCloud(CLOUD_GAIN * (0.6 + 0.4 * w));
    }
    renderer.render(scene, camera);
    raf = requestAnimationFrame(loop);
  }
  raf = requestAnimationFrame(loop);

  function onResize() {
    const cw = canvas.clientWidth || canvas.width;
    const ch = canvas.clientHeight || canvas.height;
    camera.aspect = cw / ch;
    camera.updateProjectionMatrix();
    renderer.setSize(cw, ch, false);
    cloudMat.uniforms.uPixelRatio.value = renderer.getPixelRatio();
  }
  window.addEventListener('resize', onResize);

  return {
    advance() {
      if (stage < MAX_STAGE) {
        stage++;
        targetT = stage;
        return true;
      }
      return false;
    },
    retreat() {
      if (stage > 0) {
        stage--;
        targetT = stage;
        return true;
      }
      return false;
    },
    dispose() {
      cancelAnimationFrame(raf);
      window.removeEventListener('resize', onResize);
      sphereGeo.dispose();
      faceGeo.dispose();
      cloudGeo.dispose();
      cloudMat.dispose();
      xAxisGeo.dispose();
      yAxisGeo.dispose();
      zAxisGeo.dispose();
      sphereMat.dispose();
      xAxisMat.dispose();
      yAxisMat.dispose();
      zAxisMat.dispose();
      for (const m of faceMats) m.dispose();
      for (const t of textures) t.dispose();
      renderer.dispose();
    },
  };
}
